\noindent\textbf{[2024 Oct/Nov, 0580/33, Question 1]}\par

\begin{parts}
\item 
\begin{subparts}
    \item Li has \$20. \\
    A box of cereal costs \$2.29. \\
    Work out the maximum number of boxes of cereal that Li can buy.
    \AnswerLine[][]
    \Marks{2}

    \item Each box of cereal has mass 615~g. \\
    Work out the total mass of 5 boxes of cereal. \\
    Give your answer in kilograms.
    \AnswerLine[][\text{kg}]
    \Marks{2}

    \item The box of cereal is a cuboid. \\
    The cuboid measures 25~cm by 20~cm by 5~cm. \\
    Work out the volume of the cuboid.
    \AnswerLine[][$\text{cm}^3$]
    \Marks{1}
\end{subparts}

\item A cereal bar is in a box. \\
The box is a cuboid measuring 6~cm by 3~cm by 1~cm.
\relinput{Figures/Q01b-1.tex}
On the 1~cm$^2$ grid, complete a net of the cuboid. \\
One face has been drawn for you.
\relinput{Figures/Q01b-2.tex}
\Marks{3}

\item The cereal contains fat, protein, carbohydrate and fibre. \\
The pie chart shows the information about the masses of fat and protein.
\relinput{Figures/Q01c.tex}
\begin{subparts}
    \item Work out the percentage of the mass of the cereal that is fat.
    \AnswerLine[][\%]
    \Marks{1}

    \item 60\% of the mass of the cereal is carbohydrate. \\
    Complete the pie chart.
    \Marks{2}

    \item Work out the mass of protein in 30~g of the cereal.
    \AnswerLine[][\text{g}]
    \Marks{2}
\end{subparts}
\end{parts}

\noindent\textbf{[2024 Oct/Nov, 0580/33, Question 2]}\par

\begin{parts}
\item Write the number 845\,024 in words.
\AnswerLine[][]
\Marks{1}

\item Write these numbers in order, starting with the smallest.
\[ \frac{7}{18} \quad 39\% \quad 0.388 \quad \frac{15}{40} \]
\AnswerLine[][\dots < \dots < \dots < \dots]
\Marks{2}

\item Find the value of
\begin{subparts}
    \item $4^5$
    \AnswerLine[][]
    \Marks{1}

    \item $6^0$
    \AnswerLine[][]
    \Marks{1}

    \item $\sqrt{16 \times 49}$
    \AnswerLine[][]
    \Marks{1}
\end{subparts}

\item Solve.
\[ 6x + 5 = 29 \]
\AnswerLine[][x =]
\Marks{2}

\item By writing each number in the calculation correct to 1 significant figure, find an estimate for the value of
\[ \frac{2.7 \times 42.4}{8.6 - 4.3} \]
You must show all your working.
\AnswerLine[][]
\Marks{2}

\item $3^5 \times 3^x = 3^{20}$. \\
Find the value of $x$.
\AnswerLine[][x =]
\Marks{1}

\item Simplify $(x^4)^3$.
\AnswerLine[][]
\Marks{1}

\item A boat to town $A$ leaves a port every 16 minutes. \\
A boat to town $B$ leaves the same port every 34 minutes. \\
Both boats leave the port at 07 30. \\
Work out the next time both boats leave the port together.
\AnswerLine[][]
\Marks{3}
\end{parts}

\noindent\textbf{[2024 Oct/Nov, 0580/33, Question 3]}\par

\begin{parts}
\item A wedding invitation is in the shape of a rectangle. \\
Draw the lines of symmetry on this rectangle.
\relinput{Figures/Q03a.tex}
\Marks{2}

\item There are 98 adults and 56 children at the wedding. \\
Find the fraction of people who are children. \\
Give your fraction in its simplest form.
\AnswerLine[][]
\Marks{2}

\item The wedding meal starts at 13 15 and lasts for 2 hours 50 minutes. \\
Find the time the meal ends.
\AnswerLine[][]
\Marks{1}

\item The probability that it will rain at the wedding is 0.12. \\
Find the probability that it will not rain.
\AnswerLine[][]
\Marks{1}

\item 
\begin{subparts}
    \item These are the ages of the staff at the wedding.
    \[ 16 \quad 24 \quad 39 \quad 28 \quad 17 \quad 48 \quad 31 \quad 33 \quad 17 \quad 29 \quad 40 \quad 25 \]
    Complete the stem-and-leaf diagram.
    \relinput{Figures/Q03ei.tex}
    \Marks{2}

    \item Find the range.
    \AnswerLine[][]
    \Marks{1}
\end{subparts}
\end{parts}

\noindent\textbf{[2024 Oct/Nov, 0580/33, Question 4]}\par

\begin{parts}
\item $n = 15r + 20c$ \\
Find the value of $r$ when $n = 180$ and $c = 3$.
\AnswerLine[][r =]
\Marks{2}

\item Factorise completely.
\[ 20p^2q - 5p \]
\AnswerLine[][]
\Marks{2}

\item Apples cost 35 cents each and bananas cost 14 cents each. \\
Write down an expression for the total cost, in cents, of $x$ apples and $y$ bananas.
\AnswerLine[][\text{cents}]
\Marks{2}

\item Solve the simultaneous equations. \\
You must show all your working.
\begin{align*}
    8x + 3y &= 59 \\
    5x + 7y &= 83
\end{align*}
\AnswerLine[][x =]
\AnswerLine[][y =]
\Marks{4}
\end{parts}

\noindent\textbf{[2024 Oct/Nov, 0580/33, Question 5]}\par

\begin{parts}
\item Kurt owns some toy cars of different colours. \\
The pictogram shows the number of each colour.
\relinput{Figures/Q05a.tex}
\begin{subparts}
    \item Write down the colour of toy car that Kurt owns most of.
    \AnswerLine[][]
    \Marks{1}

    \item Find the number of yellow toy cars that Kurt owns.
    \AnswerLine[][]
    \Marks{1}

    \item Find how many more red toy cars than white toy cars Kurt owns.
    \AnswerLine[][]
    \Marks{1}
\end{subparts}

\item Leo buys 75 cars. \\
The cost of each car is 1.48 euros. \\
The exchange rate is 1 euro = \$1.07. \\
Work out the total cost of the 75 cars in dollars.
\AnswerLine[][\$]
\Marks{3}

\item Leo owns some toy vehicles. \\
He owns 57 cars, 12 bicycles and 42 trucks. \\
Find the ratio of the number of $\text{cars} : \text{bicycles} : \text{trucks}$ in its simplest form.
\AnswerLine[][\dots : \dots : \dots]
\Marks{2}

\item Leo keeps his toy vehicles on a shelf.
\begin{subparts}
    \item The shelf is in the shape of a right-angled triangle.
    \relinput{Figures/Q05di.tex}
    The area of the shelf is 0.3~m$^2$. \\
    Calculate the value of $y$.
    \AnswerLine[][y =]
    \Marks{2}

    \item The shelf is 1.35 metres from the floor. \\
    Change 1.35 metres into centimetres.
    \AnswerLine[][\text{cm}]
    \Marks{1}
\end{subparts}
\end{parts}

