\noindent\textbf{[2024 Oct/Nov, 0580/33, Question 6]}\par

\begin{parts}
\item The diagram shows a plan of Zak's garden.
\relinput{Figures/Q06a.tex}
Find the perimeter of the garden.
\AnswerLine[][\text{m}]
\Marks{2}

\item Zak records the temperature in his garden each night for one week.
\relinput{Figures/Q06b.tex}
\begin{center}
\begin{tabular}{|c|c|c|c|c|c|c|}
\hline
Sunday & Monday & Tuesday & Wednesday & Thursday & Friday & Saturday \\ \hline
$4^\circ\text{C}$ & $1^\circ\text{C}$ & $-2^\circ\text{C}$ & $2^\circ\text{C}$ & $-5^\circ\text{C}$ & $3^\circ\text{C}$ & $-4^\circ\text{C}$ \\ \hline
\end{tabular}
\end{center}

\begin{subparts}
    \item Which night was coldest?
    \AnswerLine[][]
    \Marks{1}

    \item Find the difference in temperature between Friday night and Saturday night.
    \AnswerLine[][$^\circ\text{C}$]
    \Marks{1}
\end{subparts}

\item Zak buys pea plants, bean plants and sunflower plants in the ratio \\
$\text{peas} : \text{beans} : \text{sunflowers} = 7 : 5 : 2$. \\
He buys 45 bean plants. \\
Show that the total number of plants he buys is 126.
\Marks{2}

\item Zak has a water barrel. \\
On Monday the barrel contains 120 litres of water. \\
On Friday the barrel contains 43.2 litres of water. \\
Calculate the percentage decrease of the water in the barrel.
\AnswerLine[][\%]
\Marks{2}

\item Zak drives to a shop. \\
The journey takes $1\frac{1}{4}$ hours. \\
He drives at an average speed of 57~km/h. \\
Calculate the distance he drives.
\AnswerLine[][\text{km}]
\Marks{2}

\item Zak pays \$69.80 to hire a machine.
\relinput{Figures/Q06f.tex}
\begin{center}
\begin{tabular}{|l|c|}
\hline
\multicolumn{2}{|c|}{Machine hire charges} \\ \hline
1st day               & \$22.60             \\ \hline
Each additional day   & \$11.80             \\ \hline
\end{tabular}
\end{center}
Calculate the number of days he hires it for.
\AnswerLine[][\text{days}]
\Marks{3}
\end{parts}

\noindent\textbf{[2024 Oct/Nov, 0580/33, Question 7]}\par

\begin{parts}
\item
\relinput{Figures/Q07a.tex}
Write down the mathematical name for this solid.
\AnswerLine[][]
\Marks{1}

\item
\relinput{Figures/Q07b.tex}
\begin{subparts}
    \item Measure the size of angle $x$.
    \AnswerLine[][]
    \Marks{1}

    \item Write down the mathematical name for this type of angle.
    \AnswerLine[][]
    \Marks{1}
\end{subparts}

\item
\relinput{Figures/Q07c.tex}
Points $A$, $B$ and $C$ lie on the circle, centre $O$. \\
$AB = 11$~cm and $BC = 5$~cm.
\begin{subparts}
    \item Give a geometrical reason why angle $ACB$ is $90^\circ$.
    \AnswerLine[][]
    \Marks{1}

    \item Calculate the circumference of the circle.
    \AnswerLine[][\text{cm}]
    \Marks{2}

    \item Show that $AC$ is 9.8~cm, correct to 2 significant figures.
    \Marks{3}
\end{subparts}

\item The surface area of a sphere is 250~cm$^2$. \\
Calculate the radius of the sphere. \\
{[The surface area, $A$, of a sphere with radius $r$ is $A = 4\pi r^2$.]}
\AnswerLine[][\text{cm}]
\Marks{3}
\end{parts}

