\begin{parts}
\item 
\begin{subparts}
    \item Complete the table of values for $y = 4x - x^2$.
    \relinput{Figures/Q08ai.tex}
    \begin{center}
    \begin{tabular}{|l|c|c|c|c|c|c|c|c|}
    \hline
    $x$ & $-1$ & 0 & 1 & 2 & 3 & 4 & 5 & 6 \\ \hline
    $y$ & $-5$ & 0 & 3 & 4 & 3 &   & $-5$ & \\ \hline
    \end{tabular}
    \end{center}
    \Marks{2}

    \item On the grid, draw the graph of $y = 4x - x^2$ for $-1 \le x \le 6$.
    \relinput{Figures/Q08aii.tex}
    \Marks{4}

    \item Use your graph to solve the equation $4x - x^2 = 1$.
    \AnswerLine[][x = \dots \text{ or } x = \dots]
    \Marks{2}
\end{subparts}

\item The line $L$ is shown on the grid.
\relinput{Figures/Q08b.tex}
Find the equation of line $L$.
\AnswerLine[][]
\Marks{3}

\end{parts}

\noindent\textbf{[2024 Oct/Nov, 0580/33, Question 9]}\par

Shapes $A$, $B$ and $C$ are shown on the grid.
\relinput{Figures/Q09.tex}

\begin{parts}
\item Write down the mathematical name of shape $A$.
\AnswerLine[][]
\Marks{1}

\item Describe fully the single transformation that maps shape $A$ onto shape $B$.
\AnswerLine[][]
\Marks{3}

\item Describe fully the single transformation that maps shape $A$ onto shape $C$.
\AnswerLine[][]
\Marks{2}

\item Draw the image of shape $A$ after a rotation, $90^\circ$ clockwise, centre $(0, 0)$.
\Marks{2}

\item Draw the image of shape $A$ after a reflection in the line $x = 1$.
\Marks{2}
\end{parts}
